/* KCNA authoritative references - official documentation per domain. Auto-generated, verified URLs. */
KCNA.registerReferences("fundamentals", [{"topic": "Containers & OCI images", "title": "Images | Kubernetes", "url": "https://kubernetes.io/docs/concepts/containers/images/", "note": "Explains container images, registries, image names/tags/digests, multi-architecture image indexes, and image pull policies (IfNotPresent/Always/Never), all core KCNA knowledge for how Kubernetes consumes OCI images."}, {"topic": "Containers & OCI images", "title": "OCI Image Format Specification | Open Container Initiative", "url": "https://specs.opencontainers.org/image-spec/", "note": "The authoritative OCI specification defining the image manifest, image index, filesystem layers, and config that make container images interoperable; useful for KCNA's emphasis on open standards and the CNCF/OCI ecosystem."}, {"topic": "Containers (general concept)", "title": "Containers | Kubernetes", "url": "https://kubernetes.io/docs/concepts/containers/", "note": "Overview of what containers are in Kubernetes, their immutable/stateless nature, and how images and runtimes fit together; a good single entry point for the container fundamentals KCNA expects."}, {"topic": "Container runtimes", "title": "Container Runtimes | Kubernetes", "url": "https://kubernetes.io/docs/setup/production-environment/container-runtimes/", "note": "Describes the supported runtimes (containerd, CRI-O, Docker Engine via cri-dockerd) and cgroup driver configuration, directly covering the 'container runtime' node component tested on KCNA."}, {"topic": "Container runtimes (CRI)", "title": "Container Runtime Interface (CRI) | Kubernetes", "url": "https://kubernetes.io/docs/concepts/architecture/cri/", "note": "Explains the CRI gRPC plugin interface that lets the kubelet talk to any conformant runtime, a key abstraction KCNA uses to explain why Kubernetes is runtime-agnostic."}, {"topic": "Pods", "title": "Pods | Kubernetes", "url": "https://kubernetes.io/docs/concepts/workloads/pods/", "note": "Defines the Pod as the smallest deployable unit, covering single- vs multi-container pods, shared network/storage, and the pod lifecycle; foundational and heavily weighted on KCNA."}, {"topic": "ReplicaSets & Deployments", "title": "Deployments | Kubernetes", "url": "https://kubernetes.io/docs/concepts/workloads/controllers/deployment/", "note": "Covers Deployments providing declarative updates, rolling updates, rollbacks, and scaling by managing ReplicaSets; the primary workload controller KCNA expects you to understand."}, {"topic": "ReplicaSets & Deployments", "title": "ReplicaSet | Kubernetes", "url": "https://kubernetes.io/docs/concepts/workloads/controllers/replicaset/", "note": "Explains how a ReplicaSet maintains a stable number of replica Pods via selectors and a pod template, clarifying the layer Deployments manage underneath for KCNA."}, {"topic": "Services", "title": "Service | Kubernetes", "url": "https://kubernetes.io/docs/concepts/services-networking/service/", "note": "Details Services as a stable abstraction over a set of Pods, including ClusterIP, NodePort, LoadBalancer, and ExternalName types plus DNS-based service discovery, core KCNA networking material."}, {"topic": "ConfigMaps & Secrets", "title": "ConfigMaps | Kubernetes", "url": "https://kubernetes.io/docs/concepts/configuration/configmap/", "note": "Describes storing non-confidential key/value configuration decoupled from images, consumed as env vars, args, or volume files (with the 1 MiB limit); a standard KCNA configuration topic."}, {"topic": "ConfigMaps & Secrets", "title": "Secrets | Kubernetes", "url": "https://kubernetes.io/docs/concepts/configuration/secret/", "note": "Covers Secrets for sensitive data (passwords, tokens, keys), the built-in Secret types, and the important caveat that they are base64-encoded and stored unencrypted in etcd by default, frequently tested on KCNA."}, {"topic": "Namespaces & labels", "title": "Namespaces | Kubernetes", "url": "https://kubernetes.io/docs/concepts/overview/working-with-objects/namespaces/", "note": "Explains namespaces for isolating groups of resources, the four initial namespaces (default, kube-system, kube-public, kube-node-lease), and which objects are cluster-scoped; core KCNA organization concept."}, {"topic": "Namespaces & labels", "title": "Labels and Selectors | Kubernetes", "url": "https://kubernetes.io/docs/concepts/overview/working-with-objects/labels/", "note": "Defines labels as key/value pairs and the equality-based and set-based selectors used to group and select objects, the mechanism that links Services, ReplicaSets, and Deployments to Pods on KCNA."}, {"topic": "Control plane components", "title": "Kubernetes Components | Kubernetes", "url": "https://kubernetes.io/docs/concepts/overview/components/", "note": "The canonical overview listing control plane components (kube-apiserver, etcd, kube-scheduler, kube-controller-manager, cloud-controller-manager) and node components (kubelet, kube-proxy, runtime); the single most exam-relevant architecture page for KCNA."}, {"topic": "Control plane & node components (detail)", "title": "Cluster Architecture | Kubernetes", "url": "https://kubernetes.io/docs/concepts/architecture/", "note": "Goes deeper than the components overview, explaining how the control plane and worker nodes interact, plus addons; useful for KCNA questions on cluster topology and high availability."}, {"topic": "The Kubernetes API", "title": "The Kubernetes API | Kubernetes", "url": "https://kubernetes.io/docs/concepts/overview/kubernetes-api/", "note": "Describes the API server's RESTful HTTP API as the core of the control plane through which all components and users query and mutate object state, a central KCNA concept for the declarative model."}, {"topic": "Storage volumes & PersistentVolumes", "title": "Volumes | Kubernetes", "url": "https://kubernetes.io/docs/concepts/storage/volumes/", "note": "Covers volumes that let containers in a Pod share and access data, including ephemeral types like emptyDir and configMap and how volumes are mounted; the entry point for KCNA storage fundamentals."}, {"topic": "Storage volumes & PersistentVolumes", "title": "Persistent Volumes | Kubernetes", "url": "https://kubernetes.io/docs/concepts/storage/persistent-volumes/", "note": "Explains PersistentVolumes, PersistentVolumeClaims, static vs dynamic provisioning, StorageClasses, and the binding/reclaim lifecycle that decouples storage from Pod lifetime, a key KCNA storage topic."}]);
KCNA.registerReferences("orchestration", [{"topic": "CRI & containerd", "title": "Container Runtime Interface (CRI) | Kubernetes", "url": "https://kubernetes.io/docs/concepts/containers/cri/", "note": "Explains how the kubelet uses the CRI gRPC plugin interface to drive container runtimes like containerd; KCNA expects you to know that CRI decouples Kubernetes from any single runtime."}, {"topic": "CRI & containerd", "title": "Container Runtimes | Kubernetes", "url": "https://kubernetes.io/docs/setup/production-environment/container-runtimes/", "note": "Covers installing and configuring CRI-compatible runtimes (containerd, CRI-O) and the post-dockershim landscape; useful KCNA background on which runtimes implement CRI and why Docker was removed."}, {"topic": "CNI networking", "title": "Network Plugins | Kubernetes", "url": "https://kubernetes.io/docs/concepts/extend-kubernetes/compute-storage-net/network-plugins/", "note": "Describes how CNI plugins implement the Kubernetes pod network model (IP allocation, pod-to-pod connectivity); KCNA tests awareness that a CNI plugin is required and runtimes (not kubelet) invoke it."}, {"topic": "Ingress", "title": "Ingress | Kubernetes", "url": "https://kubernetes.io/docs/concepts/services-networking/ingress/", "note": "Defines the Ingress API object for HTTP/HTTPS routing, host/path rules, TLS termination, and the need for an ingress controller; core KCNA networking concept distinguishing Ingress from Service."}, {"topic": "NetworkPolicy", "title": "Network Policies | Kubernetes", "url": "https://kubernetes.io/docs/concepts/services-networking/network-policies/", "note": "Explains L3/L4 pod traffic control via ingress/egress rules and selectors, and that enforcement requires a supporting CNI; KCNA expects understanding of default-allow vs. isolated, additive policy behavior."}, {"topic": "service mesh", "title": "Service Mesh | CNCF Cloud Native Glossary", "url": "https://glossary.cncf.io/service-mesh/", "note": "CNCF's vendor-neutral definition of a service mesh as a dedicated infrastructure layer (often sidecar proxies) for service-to-service traffic, security, and observability; the authoritative KCNA reference for the concept."}, {"topic": "CSI storage", "title": "Volumes | Kubernetes", "url": "https://kubernetes.io/docs/concepts/storage/volumes/", "note": "Catalogs Kubernetes volume types and presents CSI as the standard out-of-tree interface for exposing external storage to pods; KCNA expects you to recognize CSI as the storage equivalent of CRI/CNI."}, {"topic": "RBAC & authentication/authorization", "title": "Using RBAC Authorization | Kubernetes", "url": "https://kubernetes.io/docs/reference/access-authn-authz/rbac/", "note": "Details the four RBAC objects (Role, ClusterRole, RoleBinding, ClusterRoleBinding) and least-privilege practice; central KCNA authorization topic for granting permissions to users and service accounts."}, {"topic": "RBAC & authentication/authorization", "title": "Controlling Access to the Kubernetes API | Kubernetes", "url": "https://kubernetes.io/docs/reference/access-authn-authz/", "note": "Overview hub for the API access pipeline (authentication, authorization, admission control) including RBAC, ABAC, Node, and Webhook modes; gives KCNA candidates the full authn-then-authz flow."}, {"topic": "4Cs of cloud native security & Pod Security Standards", "title": "Cloud Native Security and Kubernetes | Kubernetes", "url": "https://kubernetes.io/docs/concepts/security/cloud-native-security/", "note": "Official home for Kubernetes' cloud native security model and the CNCF security white paper; presents security across the workload lifecycle (Develop, Distribute, Deploy, Runtime) and the layered Cloud/Cluster/Container/Code thinking behind the 4Cs. Foundational KCNA security context."}, {"topic": "4Cs of cloud native security & Pod Security Standards", "title": "Pod Security Standards | Kubernetes", "url": "https://kubernetes.io/docs/concepts/security/pod-security-standards/", "note": "Defines the three cumulative policies Privileged, Baseline, and Restricted enforced via Pod Security Admission; a frequently tested KCNA security topic for hardening pods."}, {"topic": "scheduling & affinity", "title": "Assigning Pods to Nodes | Kubernetes", "url": "https://kubernetes.io/docs/concepts/scheduling-eviction/assign-pod-node/", "note": "Covers nodeSelector, node affinity (required/preferred), and inter-pod affinity/anti-affinity for constraining scheduling; the core KCNA reference for how the scheduler places pods."}, {"topic": "scheduling & affinity", "title": "Taints and Tolerations | Kubernetes", "url": "https://kubernetes.io/docs/concepts/scheduling-eviction/taint-and-toleration/", "note": "Explains taints that repel pods from nodes and tolerations that permit scheduling, the inverse of affinity; KCNA pairs this with affinity to complete the scheduling-control picture."}, {"topic": "autoscaling within orchestration", "title": "Autoscaling Workloads | Kubernetes", "url": "https://kubernetes.io/docs/concepts/workloads/autoscaling/", "note": "Overview of horizontal vs. vertical pod autoscaling plus event- and schedule-driven approaches; gives KCNA candidates the map of how Kubernetes elastically scales workloads to demand."}, {"topic": "autoscaling within orchestration", "title": "Horizontal Pod Autoscaling | Kubernetes", "url": "https://kubernetes.io/docs/concepts/workloads/autoscaling/horizontal-pod-autoscale/", "note": "Details the HorizontalPodAutoscaler controller, its metric-driven replica algorithm, and limits (e.g. not for DaemonSets); the canonical KCNA reference for the most-tested autoscaling mechanism."}]);
KCNA.registerReferences("architecture", [{"topic": "autoscaling (HPA, VPA, Cluster Autoscaler)", "title": "Autoscaling Workloads | Kubernetes", "url": "https://kubernetes.io/docs/concepts/workloads/autoscaling/", "note": "Official overview of all Kubernetes autoscaling approaches (HPA, VPA, cluster-proportional, event-driven/KEDA, and node autoscaling) in one place, which is exactly the breadth KCNA tests on the difference between scaling pods horizontally, vertically, and scaling the cluster. Verified: live page titled 'Autoscaling Workloads' covering manual scaling, HPA, VPA, cluster-proportional, KEDA event/schedule-driven, and node infrastructure scaling."}, {"topic": "autoscaling (Cluster Autoscaler / node autoscaling)", "title": "Node Autoscaling | Kubernetes", "url": "https://kubernetes.io/docs/concepts/cluster-administration/node-autoscaling/", "note": "Dedicated page contrasting the Cluster Autoscaler (node-group based) with Karpenter for adding and consolidating nodes; useful for the KCNA distinction between workload autoscaling and infrastructure (node) autoscaling. Verified: live page titled 'Node Autoscaling' covering node provisioning, consolidation, and both Cluster Autoscaler and Karpenter."}, {"topic": "serverless & Knative", "title": "About autoscaling - Knative", "url": "https://knative.dev/docs/serving/autoscaling/", "note": "Official Knative docs explaining serverless autoscaling, scale-to-zero, and the Knative Pod Autoscaler (KPA) vs HPA, covering the serverless/scale-to-zero concepts KCNA asks about in cloud native architecture. Verified: live page titled 'About autoscaling' covering KPA, scale-to-zero, concurrency/scale bounds, and HPA alternative."}, {"topic": "CNCF landscape & governance & graduation levels", "title": "Project Lifecycle and Process | CNCF Contributors", "url": "https://contribute.cncf.io/projects/lifecycle/", "note": "Authoritative CNCF description of the sandbox, incubating, graduated (and archived) maturity levels plus the TOC due-diligence process; the graduation levels are a frequently tested KCNA fact. Verified: live page titled 'Project Lifecycle and Process' covering the four maturity stages and the TOC evaluation/due-diligence process."}, {"topic": "CNCF governance", "title": "Who We Are | CNCF", "url": "https://www.cncf.io/about/who-we-are/", "note": "Official CNCF page on its mission and governance bodies (Governing Board, Technical Oversight Committee, End User TAB) and its role as a vendor-neutral Linux Foundation home, which grounds the KCNA 'CNCF and its role' objectives. Verified: live page titled 'Who We Are' covering CNCF mission, the three governance bodies, and its place under the Linux Foundation."}, {"topic": "open standards (CNI, CSI, CRI / device plugins)", "title": "Compute, Storage, and Networking Extensions | Kubernetes", "url": "https://kubernetes.io/docs/concepts/extend-kubernetes/compute-storage-net/", "note": "Official index page for the pluggable interfaces (CSI for storage, CNI/network plugins, device plugins) that let Kubernetes work with any backend; central to the KCNA open-standards and extensibility theme. Verified: live page titled 'Compute, Storage, and Networking Extensions' covering CSI/FlexVolume storage plugins, device plugins, and CNI network plugins."}, {"topic": "open standards (CRI)", "title": "Container Runtime Interface (CRI) | Kubernetes", "url": "https://kubernetes.io/docs/concepts/architecture/cri/", "note": "Official explanation of the gRPC-based Container Runtime Interface between the kubelet and runtimes like containerd/CRI-O; KCNA expects you to know CRI as the open standard that decouples Kubernetes from a specific runtime. Verified: live page titled 'Container Runtime Interface (CRI)' describing the gRPC plugin interface between kubelet and container runtimes."}, {"topic": "open standards (OCI)", "title": "About the Open Container Initiative", "url": "https://opencontainers.org/about/overview/", "note": "Authoritative OCI overview of the runtime-spec, image-spec, and distribution-spec that standardize container formats and runtimes; OCI is the canonical open container standard referenced throughout KCNA. Verified: live page titled 'About the Open Container Initiative' covering OCI governance and the runtime-spec, image-spec, and distribution-spec."}, {"topic": "microservices patterns", "title": "Microservices Architecture | Cloud Native Glossary", "url": "https://glossary.cncf.io/microservices-architecture/", "note": "CNCF Glossary definition of microservices architecture, its benefits (independent deploy/scale), and trade-offs vs monoliths; the vendor-neutral framing KCNA uses for cloud native application architecture. Verified: live page titled 'Microservices Architecture' covering the definition, benefits vs monoliths, and operational trade-offs."}, {"topic": "cost management / FinOps", "title": "FinOps for Kubernetes: engineering cost optimization | CNCF", "url": "https://www.cncf.io/blog/2024/04/29/finops-for-kubernetes-engineering-cost-optimization/", "note": "CNCF article on applying FinOps to Kubernetes (cost drivers, tagging/chargeback, eliminating idle waste); covers the cost-management/FinOps concepts that appear under cloud native architecture in KCNA. Verified: live article titled 'FinOps for Kubernetes: engineering cost optimization' covering cost drivers, tagging/chargeback, and idle/over-provisioning waste."}, {"topic": "cost management / FinOps tooling", "title": "CNCF & FinOps Foundation Collaborate to Advance Cloud Financial Management", "url": "https://www.cncf.io/announcements/2020/11/17/cncf-and-finops-foundation-collaborate-to-advance-cloud-financial-management/", "note": "Official CNCF announcement establishing the FinOps Foundation collaboration under the Linux Foundation, giving authoritative context for what FinOps is and why cloud native cost management matters for KCNA. Verified: live announcement titled 'CNCF and FinOps Foundation Collaborate to Advance Cloud Financial Management' covering the partnership, container cost allocation, and FinOps Foundation under the Linux Foundation."}, {"topic": "Three pillars (logs, metrics, traces)", "title": "Observability Primer | OpenTelemetry", "url": "https://opentelemetry.io/docs/concepts/observability-primer/", "note": "Vendor-neutral CNCF page that defines observability and explains the core telemetry signals (logs, metrics, traces) plus reliability/SLI/SLO context, making it the cleanest primer for the KCNA observability 'three pillars' concept. Verified: live, title 'Observability primer', defines observability and logs/metrics/traces."}, {"topic": "Three pillars (signals detail)", "title": "Signals | OpenTelemetry", "url": "https://opentelemetry.io/docs/concepts/signals/", "note": "Breaks down each OpenTelemetry signal (traces, metrics, logs, plus baggage) with crisp definitions; useful for KCNA to distinguish what each pillar measures and how they complement each other. Verified: live, title 'Signals', covers traces/metrics/logs/baggage."}, {"topic": "Prometheus", "title": "Overview | Prometheus", "url": "https://prometheus.io/docs/introduction/overview/", "note": "Official Prometheus intro describing it as the CNCF graduated open-source monitoring and alerting toolkit that stores metrics as labeled time series and queries them with PromQL; Prometheus is the de facto metrics standard tested on KCNA. Verified: live, title 'Overview | Prometheus', covers time series, labels, PromQL."}, {"topic": "Prometheus (concepts)", "title": "What is Prometheus? | Grafana documentation", "url": "https://grafana.com/docs/grafana/latest/fundamentals/intro-to-prometheus/", "note": "Beginner-friendly walkthrough of Prometheus fundamentals (time series, samples/labels, PromQL, metric types, scraping/exporters); good reinforcement of metrics concepts for a KCNA learner. Verified: live, title 'What is Prometheus? | Grafana documentation', covers time series, labels, PromQL, metric types, scraping."}, {"topic": "OpenTelemetry", "title": "What is OpenTelemetry? | OpenTelemetry", "url": "https://opentelemetry.io/docs/what-is-opentelemetry/", "note": "Official definition of OpenTelemetry (OTel) as the vendor-neutral CNCF framework for generating, collecting, and exporting traces, metrics, and logs; clarifies it is instrumentation, not a backend, which is a common KCNA exam point. Verified: live, title 'What is OpenTelemetry?', confirms vendor-neutral framework for traces/metrics/logs and that it is not a backend."}, {"topic": "Grafana", "title": "About Grafana | Grafana documentation", "url": "https://grafana.com/docs/grafana/latest/introduction/", "note": "Official Grafana intro describing the open-source platform for querying, visualizing, alerting on, and exploring metrics, logs, and traces; Grafana is the canonical visualization layer paired with Prometheus in cloud native observability. Verified: live, title 'About Grafana | Grafana documentation', confirms query/visualize/alert/explore on metrics, logs, and traces."}, {"topic": "SLI / SLO / SLA", "title": "Service Level Objectives | Google SRE Book (Chapter 4)", "url": "https://sre.google/sre-book/service-level-objectives/", "note": "Authoritative Google SRE source defining SLI (a quantitative measure of service), SLO (a target for that SLI), and SLA (a contract with consequences), plus error budgets; the foundational reference for these KCNA reliability terms. Verified: live, title 'Chapter 4 - Service Level Objectives', defines SLI/SLO/SLA and error budgets."}, {"topic": "OpenMetrics", "title": "OpenMetrics 1.0 Specification | Prometheus", "url": "https://prometheus.io/docs/specs/om/open_metrics_spec/", "note": "The official OpenMetrics 1.0 specification (now under the Prometheus project) defining the open standard exposition format for metrics, including metric types and the /metrics text format; relevant for KCNA's metrics-format knowledge. Verified: live, title 'OpenMetrics 1.0', defines the metrics exposition format, data model, metric types, and wire formats."}, {"topic": "OpenMetrics (CNCF history)", "title": "OpenMetrics is archived, merged into Prometheus | CNCF", "url": "https://www.cncf.io/blog/2024/09/18/openmetrics-is-archived-merged-into-prometheus/", "note": "CNCF post explaining OpenMetrics' origin as a CNCF project to standardize the Prometheus exposition format and its 2024 merge back into Prometheus; useful context so KCNA learners understand OpenMetrics' current status. Verified: live, title 'OpenMetrics is archived, merged into Prometheus', explains the 2024 archival/merge."}]);
KCNA.registerReferences("delivery", [{"topic": "CI/CD pipelines", "title": "Continuous Delivery (CD) | CNCF Cloud Native Glossary", "url": "https://glossary.cncf.io/continuous-delivery/", "note": "Official CNCF glossary definition of continuous delivery, explaining how code changes are automatically tested and deployed with rollback support — a core CI/CD concept the KCNA exam tests directly."}, {"topic": "CI/CD pipelines", "title": "Continuous Integration (CI) | CNCF Cloud Native Glossary", "url": "https://glossary.cncf.io/continuous-integration/", "note": "Official CNCF glossary definition of continuous integration and how it produces a tested artifact feeding the CD pipeline; pairs with the CD entry to cover the full CI/CD vocabulary KCNA expects."}, {"topic": "GitOps (concept)", "title": "GitOps | CNCF Cloud Native Glossary", "url": "https://glossary.cncf.io/gitops/", "note": "Vendor-neutral CNCF definition of GitOps as continuously reconciling desired state in Git against actual cluster state — the conceptual baseline before learning specific tools like Argo CD and Flux."}, {"topic": "GitOps (Argo CD)", "title": "Argo CD - Declarative GitOps CD for Kubernetes (docs home)", "url": "https://argo-cd.readthedocs.io/en/stable/", "note": "Official Argo CD documentation describing it as a declarative GitOps continuous delivery controller that syncs Git-defined state to clusters; Argo CD is a CNCF graduated project frequently referenced in KCNA delivery questions."}, {"topic": "GitOps (Argo CD)", "title": "Argo CD Getting Started", "url": "https://argo-cd.readthedocs.io/en/stable/getting_started/", "note": "Hands-on install and first-application walkthrough (namespace, manifests, guestbook sync) that grounds the abstract GitOps reconciliation loop in concrete steps useful for KCNA familiarity."}, {"topic": "GitOps (Flux)", "title": "Core Concepts | Flux", "url": "https://fluxcd.io/flux/concepts/", "note": "Official Flux documentation covering GitOps, Sources, reconciliation, the GitOps Toolkit, and bootstrap; Flux is the other CNCF graduated GitOps tool KCNA contrasts with Argo CD."}, {"topic": "Helm", "title": "Helm Docs Home", "url": "https://helm.sh/docs/", "note": "Official documentation home for Helm, the CNCF graduated Kubernetes package manager, and the authoritative entry point for charts, releases, and templating concepts tested in KCNA app-delivery questions."}, {"topic": "Helm", "title": "Helm Charts", "url": "https://helm.sh/docs/topics/charts/", "note": "Official reference on Helm chart structure (Chart.yaml, templates/, values.yaml) and the Go templating engine — the packaging mechanism KCNA asks about when distinguishing Helm from raw manifests."}, {"topic": "Kustomize", "title": "Declarative Management of Kubernetes Objects Using Kustomize | kubernetes.io", "url": "https://kubernetes.io/docs/tasks/manage-kubernetes-objects/kustomization/", "note": "Official Kubernetes docs page on Kustomize's bases/overlays, generators, and built-in kubectl -k support; the canonical source for the template-free configuration management approach KCNA contrasts with Helm."}, {"topic": "Container image build & format", "title": "opencontainers/image-spec (OCI Image Format Specification)", "url": "https://github.com/opencontainers/image-spec", "note": "Canonical OCI specification defining how container images are built, structured (manifest, layers, config), and transported across registries — the standard underlying every cloud-native image build relevant to KCNA."}, {"topic": "Container image format (spec site)", "title": "The OpenContainers Image Spec", "url": "https://specs.opencontainers.org/image-spec/", "note": "Rendered specification site for the OCI image format (manifests, descriptors, media types, layers); a cleaner read than the repo for understanding image internals the KCNA supply-chain/runtime questions assume."}, {"topic": "Supply chain security", "title": "CNCF TAG Security (cncf/tag-security)", "url": "https://github.com/cncf/tag-security", "note": "Authoritative CNCF Technical Advisory Group repository hosting the Software Supply Chain Best Practices and Secure Software Factory whitepapers; the primary CNCF source for image signing, SBOM, and provenance concepts in KCNA delivery (note: archived read-only as of Dec 2025 but still canonical)."}]);
